using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments =
    [
        new() { Id = 1, Name = "Computer Science", Abbreviation = "CS" },
        new() { Id = 2, Name = "Mathematics", Abbreviation = "MATH" },
        new() { Id = 3, Name = "Physics", Abbreviation = "PHYS" },
        new() { Id = 4, Name = "English", Abbreviation = "ENG" },
        new() { Id = 5, Name = "History", Abbreviation = "HIST" }
    ];

    private readonly List<Course> _courses =
    [
        new()
        {
            Id = 1, CourseCode = "CS 101", Title = "Introduction to Programming",
            Description = "Fundamentals of programming using C#. Covers variables, control flow, object-oriented design, and basic data structures.",
            Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", DepartmentId = 1, IsFeatured = true,
            InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of industry experience at major tech companies and has been teaching introductory CS courses for 8 years."
        },
        new()
        {
            Id = 2, CourseCode = "CS 201", Title = "Data Structures and Algorithms",
            Description = "Study of fundamental data structures (trees, graphs, hash tables) and algorithm design techniques (divide and conquer, dynamic programming).",
            Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM", DepartmentId = 1, IsFeatured = true,
            InstructorName = "Dr. James Okafor", InstructorBio = "Dr. Okafor's research focuses on algorithm optimization. He has published over 40 papers in top-tier conferences."
        },
        new()
        {
            Id = 3, CourseCode = "CS 310", Title = "Software Engineering",
            Description = "Principles of software development including requirements analysis, design patterns, testing, and agile methodologies.",
            Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", DepartmentId = 1, IsFeatured = false,
            InstructorName = "Prof. Maria Santos", InstructorBio = "Prof. Santos spent 20 years in software consulting before joining academia. She specializes in large-scale system design."
        },
        new()
        {
            Id = 4, CourseCode = "MATH 101", Title = "Calculus I",
            Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics and engineering.",
            Credits = 4, Schedule = "Mon/Tue/Wed/Thu 8:00–8:50 AM", DepartmentId = 2, IsFeatured = true,
            InstructorName = "Dr. Robert Kim", InstructorBio = "Dr. Kim is an award-winning educator known for making calculus accessible to all students."
        },
        new()
        {
            Id = 5, CourseCode = "MATH 220", Title = "Linear Algebra",
            Description = "Vector spaces, linear transformations, matrices, determinants, eigenvalues, and applications.",
            Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", DepartmentId = 2, IsFeatured = false,
            InstructorName = "Dr. Elena Volkov", InstructorBio = "Dr. Volkov's research in applied mathematics has applications in machine learning and data science."
        },
        new()
        {
            Id = 6, CourseCode = "PHYS 101", Title = "General Physics I",
            Description = "Mechanics, thermodynamics, and waves. Includes weekly lab sessions with hands-on experiments.",
            Credits = 4, Schedule = "Mon/Wed/Fri 11:00–11:50 AM + Thu Lab 2:00–4:50 PM", DepartmentId = 3, IsFeatured = false,
            InstructorName = "Dr. Michael Torres", InstructorBio = "Dr. Torres is an experimental physicist whose research focuses on condensed matter physics."
        },
        new()
        {
            Id = 7, CourseCode = "PHYS 250", Title = "Quantum Mechanics",
            Description = "Introduction to quantum theory: wave functions, Schrödinger equation, uncertainty principle, and atomic structure.",
            Credits = 3, Schedule = "Tue/Thu 3:00–4:20 PM", DepartmentId = 3, IsFeatured = true,
            InstructorName = "Dr. Aisha Patel", InstructorBio = "Dr. Patel is a theoretical physicist with groundbreaking work in quantum computing applications."
        },
        new()
        {
            Id = 8, CourseCode = "ENG 101", Title = "Composition and Rhetoric",
            Description = "Developing clear, effective academic writing through essays, research papers, and peer review.",
            Credits = 3, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", DepartmentId = 4, IsFeatured = false,
            InstructorName = "Prof. David Wright", InstructorBio = "Prof. Wright is a published author and has guided thousands of students in developing their writing voice."
        },
        new()
        {
            Id = 9, CourseCode = "ENG 315", Title = "American Literature",
            Description = "Survey of American literary works from the colonial period to the present, exploring themes of identity and culture.",
            Credits = 3, Schedule = "Tue/Thu 9:00–10:20 AM", DepartmentId = 4, IsFeatured = false,
            InstructorName = "Dr. Lisa Chang", InstructorBio = "Dr. Chang specializes in 20th-century American fiction and has authored two books on the Harlem Renaissance."
        },
        new()
        {
            Id = 10, CourseCode = "HIST 101", Title = "World History to 1500",
            Description = "Survey of major civilizations, cultural exchanges, and transformative events from antiquity to the early modern period.",
            Credits = 3, Schedule = "Mon/Wed 3:30–4:50 PM", DepartmentId = 5, IsFeatured = false,
            InstructorName = "Dr. Thomas Andersen", InstructorBio = "Dr. Andersen is an archaeologist-turned-historian who brings artifacts and primary sources into the classroom."
        }
    ];

    private readonly List<EnrollmentRequest> _enrollmentRequests = [];

    public IReadOnlyList<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public IReadOnlyList<Course> GetCourses(string? searchTerm = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.CourseCode.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public IReadOnlyList<Course> GetFeaturedCourses() =>
        _courses.Where(c => c.IsFeatured).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public void SubmitEnrollmentRequest(EnrollmentRequest request) =>
        _enrollmentRequests.Add(request);
}

@page "/"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>University Course Catalog</PageTitle>

<h1>University Course Catalog</h1>
<p class="lead">Welcome! Browse our departments and courses, or search for specific offerings.</p>

<h2>Featured Courses</h2>
<div class="row">
    @foreach (var course in _featuredCourses)
    {
        <div class="col-md-6 col-lg-4 mb-3">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@course.CourseCode</h5>
                    <h6 class="card-subtitle mb-2 text-muted">@course.Title</h6>
                    <p class="card-text">@course.Credits credits &bull; @course.InstructorName</p>
                    <a href="/courses/@course.Id" class="btn btn-primary btn-sm">View Details</a>
                </div>
            </div>
        </div>
    }
</div>

<h2 class="mt-4">Departments</h2>
<div class="list-group">
    @foreach (var dept in _departments)
    {
        <a href="/courses?departmentId=@dept.Id" class="list-group-item list-group-item-action">
            <strong>@dept.Abbreviation</strong> &mdash; @dept.Name
        </a>
    }
</div>

@code {
    private IReadOnlyList<Course> _featuredCourses = [];
    private IReadOnlyList<Department> _departments = [];

    protected override void OnInitialized()
    {
        _featuredCourses = Catalog.GetFeaturedCourses();
        _departments = Catalog.GetDepartments();
    }
}

@page "/courses"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>Browse Courses</PageTitle>

<h1>Browse Courses</h1>

<form method="get" action="/courses" class="row g-3 mb-4">
    <div class="col-md-6">
        <label for="search" class="form-label">Search</label>
        <input type="text" id="search" name="search" value="@Search" class="form-control" placeholder="Course title, code, or instructor..." />
    </div>
    <div class="col-md-4">
        <label for="departmentId" class="form-label">Department</label>
        <select id="departmentId" name="departmentId" class="form-select">
            <option value="">All Departments</option>
            @foreach (var dept in _departments)
            {
                <option value="@dept.Id" selected="@(DepartmentId == dept.Id)">@dept.Name</option>
            }
        </select>
    </div>
    <div class="col-md-2 d-flex align-items-end">
        <button type="submit" class="btn btn-primary w-100">Filter</button>
    </div>
</form>

@if (_courses.Count == 0)
{
    <div class="alert alert-info">No courses match your criteria.</div>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped">
            <thead>
                <tr>
                    <th>Code</th>
                    <th>Title</th>
                    <th>Credits</th>
                    <th>Instructor</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var course in _courses)
                {
                    <tr>
                        <td>@course.CourseCode</td>
                        <td>@course.Title</td>
                        <td>@course.Credits</td>
                        <td>@course.InstructorName</td>
                        <td><a href="/courses/@course.Id" class="btn btn-outline-primary btn-sm">Details</a></td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    [SupplyParameterFromQuery] public string? Search { get; set; }
    [SupplyParameterFromQuery] public int? DepartmentId { get; set; }

    private IReadOnlyList<Course> _courses = [];
    private IReadOnlyList<Department> _departments = [];

    protected override void OnInitialized()
    {
        _departments = Catalog.GetDepartments();
        _courses = Catalog.GetCourses(Search, DepartmentId);
    }
}

@page "/courses/{Id:int}"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

@if (_course is null)
{
    <PageTitle>Course Not Found</PageTitle>
    <h1>Course Not Found</h1>
    <p>The requested course does not exist.</p>
    <a href="/courses" class="btn btn-secondary">Back to Courses</a>
}
else
{
    <PageTitle>@_course.CourseCode - @_course.Title</PageTitle>

    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="/courses?departmentId=@_course.DepartmentId">@_department?.Name</a></li>
            <li class="breadcrumb-item active">@_course.CourseCode</li>
        </ol>
    </nav>

    <h1>@_course.CourseCode &mdash; @_course.Title</h1>

    <div class="row mt-4">
        <div class="col-md-8">
            <h2>Description</h2>
            <p>@_course.Description</p>

            <h2>Instructor</h2>
            <h5>@_course.InstructorName</h5>
            <p>@_course.InstructorBio</p>
        </div>
        <div class="col-md-4">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">Course Details</h5>
                    <ul class="list-unstyled">
                        <li><strong>Credits:</strong> @_course.Credits</li>
                        <li class="mt-2"><strong>Schedule:</strong> @_course.Schedule</li>
                        <li class="mt-2"><strong>Department:</strong> @_department?.Name</li>
                    </ul>
                    <a href="/enroll?courseId=@_course.Id" class="btn btn-success w-100 mt-3">Request Enrollment</a>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Course? _course;
    private Department? _department;

    protected override void OnInitialized()
    {
        _course = Catalog.GetCourse(Id);
        if (_course is not null)
            _department = Catalog.GetDepartment(_course.DepartmentId);
    }
}

