}
else
{
    <p>Fill out the form below to request enrollment in a course.</p>

    <EditForm method="post" Model="Model" OnValidSubmit="HandleSubmit" FormName="enrollment" class="col-md-6">
        <AntiforgeryToken />

        <div class="mb-3">
            <label for="studentName" class="form-label">Full Name</label>
            <InputText id="studentName" @bind-Value="Model.StudentName" class="form-control" required />
        </div>

        <div class="mb-3">
            <label for="studentId" class="form-label">Student ID</label>
            <InputText id="studentId" @bind-Value="Model.StudentId" class="form-control" required placeholder="e.g., STU-12345" />
        </div>

        <div class="mb-3">
            <label for="courseId" class="form-label">Course</label>
            <InputSelect id="courseId" @bind-Value="Model.CourseId" class="form-select" required>
                <option value="0">— Select a course —</option>
                @foreach (var course in _courses)
                {
                    <option value="@course.Id">@course.CourseCode - @course.Title</option>
                }
            </InputSelect>
        </div>

        <button type="submit" class="btn btn-success">Submit Request</button>
        <a href="/courses" class="btn btn-secondary ms-2">Cancel</a>
    </EditForm>
}

@code {
    [SupplyParameterFromForm] public EnrollmentRequest Model { get; set; } = new();
    [SupplyParameterFromQuery] public int? CourseId { get; set; }

    private IReadOnlyList<Course> _courses = [];
    private bool _submitted;

    protected override void OnInitialized()
    {
        _courses = Catalog.GetCourses();

        if (CourseId.HasValue && Model.CourseId == 0)
            Model.CourseId = CourseId.Value;
    }

    private void HandleSubmit()
    {
        if (!string.IsNullOrWhiteSpace(Model.StudentName) &&
            !string.IsNullOrWhiteSpace(Model.StudentId) &&
            Model.CourseId > 0)
        {
            Catalog.SubmitEnrollmentRequest(Model);
            _submitted = true;
        }
    }
}

